// frontend/packages/ui/src/fontsource.d.ts
//
// Type declarations for locally bundled Fontsource CSS packages.
// These packages are dynamically imported by the uiFont store so the app can
// load only the selected interface font without any third-party font requests.
// Keep this file separate from broad component/YAML declarations.

declare module '@fontsource-variable/lexend-deca';
declare module '@fontsource-variable/figtree';
declare module '@fontsource-variable/rubik';
declare module '@fontsource-variable/inter';
declare module '@fontsource-variable/public-sans';
declare module '@fontsource/atkinson-hyperlegible';
declare module '@fontsource/ibm-plex-sans';
declare module '@fontsource-variable/source-serif-4';
declare module '@fontsource-variable/jetbrains-mono';
declare module '@fontsource/ibm-plex-mono';
